678	// are legacy; new rows use canonical statuses and the lifecycle state machine.
679	func beadHasLegacyLifecycleInputs(b bead.Bead) bool {
680		if b.Status == "needs_investigation" || b.Status == "needs_human" {
681			return true
682		}
683		for _, label := range b.Labels {
684			if label == bead.LabelNeedsHuman || label == bead.LabelNeedsInvestigation {
685				return true
686			}
687		}
688		return false
689	}
