16	// gqlMutation sends a GraphQL mutation and returns the raw response body.
17	func gqlMutation(t *testing.T, srv *Server, mutation string) map[string]json.RawMessage {
18		t.Helper()
19		rawBody, _ := json.Marshal(map[string]string{"query": mutation})
20		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(rawBody))
21		req.Header.Set("Content-Type", "application/json")
22		req.RemoteAddr = "127.0.0.1:12345"
23		w := httptest.NewRecorder()
24		srv.Handler().ServeHTTP(w, req)
25		if w.Code != http.StatusOK {
26			t.Fatalf("expected 200, got %d: %s", w.Code, w.Body.String())
27		}
28		var resp map[string]json.RawMessage
29		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
30			t.Fatalf("invalid JSON: %v\nbody: %s", err, w.Body.String())
31		}
32		if errs, ok := resp["errors"]; ok {
33			t.Fatalf("GraphQL errors: %s", errs)
34		}
35		return resp
36	}
