118	func writeSessionIndexLines(t *testing.T, workDir string, lines ...string) {
119		t.Helper()
120		logDir := filepath.Join(workDir, agent.DefaultLogDir)
121		if err := os.MkdirAll(logDir, 0o755); err != nil {
122			t.Fatal(err)
123		}
124		for _, line := range lines {
125			var entry agent.SessionEntry
126			if err := json.Unmarshal([]byte(line), &entry); err != nil {
127				t.Fatal(err)
128			}
129			if entry.Prompt != "" || entry.Response != "" {
130				if entry.Correlation == nil {
131					entry.Correlation = map[string]string{}
132				}
133				attemptID := entry.Correlation["attempt_id"]
134				if attemptID == "" {
135					attemptID = "session-" + entry.ID
136					entry.Correlation["attempt_id"] = attemptID
137				}
138				bundleDir := filepath.Join(workDir, agent.ExecuteBeadArtifactDir, attemptID)
139				if err := os.MkdirAll(bundleDir, 0o755); err != nil {
140					t.Fatal(err)
141				}
142				if err := os.WriteFile(filepath.Join(bundleDir, "prompt.md"), []byte(entry.Prompt), 0o644); err != nil {
143					t.Fatal(err)
144				}
145				result := map[string]string{"response": entry.Response}
146				data, err := json.Marshal(result)
147				if err != nil {
148					t.Fatal(err)
149				}
150				if err := os.WriteFile(filepath.Join(bundleDir, "result.json"), data, 0o644); err != nil {
151					t.Fatal(err)
152				}
153			}
154			idx := agent.SessionIndexEntryFromLegacy(workDir, entry)
155			var raw map[string]json.RawMessage
156			if err := json.Unmarshal([]byte(line), &raw); err != nil {
157				t.Fatal(err)
158			}
159			_, idx.CostPresent = raw["cost_usd"]
160			if err := agent.AppendSessionIndex(logDir, idx, entry.Timestamp); err != nil {
161				t.Fatal(err)
162			}
163		}
164	}
